/**
 * 智能下载器 - AI驱动的动态算法更新系统
 * 随时可以调用AI来分析、生成和更新下载策略
 */

const { spawn } = require('child_process');
const fs = require('fs');
const path = require('path');
const https = require('https');
const http = require('http');
const { URL } = require('url');
const AIClient = require('./ai_client');
const AntiScraperAI = require('./anti_scraper_ai');

class DynamicDownloader {
    constructor() {
        this.aiClient = new AIClient();
        this.antiScraper = new AntiScraperAI();
        this.algorithms = new Map(); // 缓存各平台的下载算法
        this.lastUpdate = Date.now();
    }

    /**
     * 主入口：智能下载视频
     */
    async download(url, options = {}) {
        const { forceAIAnalysis = false, outputDir = './downloads' } = options;

        // 检测平台
        const platform = this.detectPlatform(url);

        // 获取或生成下载算法
        let algorithm = this.algorithms.get(platform);

        if (!algorithm || forceAIAnalysis || this.isAlgorithmExpired(algorithm)) {
            console.log(`正在为 ${platform} 生成新的下载算法...`);
            algorithm = await this.generateAlgorithm(url, platform);
            this.algorithms.set(platform, algorithm);
        }

        // 执行下载
        return await this.executeDownload(url, algorithm, outputDir);
    }

    /**
     * 检测平台类型
     */
    detectPlatform(url) {
        const lowerUrl = url.toLowerCase();

        if (lowerUrl.includes('douyin.com') || lowerUrl.includes('iesdouyin.com')) {
            return 'douyin';
        }
        if (lowerUrl.includes('tiktok.com')) {
            return 'tiktok';
        }
        if (lowerUrl.includes('youtube.com') || lowerUrl.includes('youtu.be')) {
            return 'youtube';
        }
        if (lowerUrl.includes('bilibili.com')) {
            return 'bilibili';
        }
        if (lowerUrl.includes('weibo.com')) {
            return 'weibo';
        }
        if (lowerUrl.includes('xiaohongshu.com') || lowerUrl.includes('xhslink.com')) {
            return 'xiaohongshu';
        }

        return 'unknown';
    }

    /**
     * 使用AI生成下载算法
     */
    async generateAlgorithm(url, platform) {
        const prompt = this.buildAlgorithmPrompt(url, platform);

        try {
            const response = await this.aiClient.call(prompt, {
                systemPrompt: '你是一个视频下载算法专家。分析视频平台的反爬机制，生成可执行的Python或Node.js代码来下载视频。',
                temperature: 0.4
            });

            return this.parseAlgorithmResponse(response, platform);
        } catch (error) {
            console.error('AI生成算法失败:', error.message);
            return this.getFallbackAlgorithm(platform);
        }
    }

    /**
     * 构建算法生成提示词
     */
    buildAlgorithmPrompt(url, platform) {
        const platformInfo = {
            douyin: {
                name: '抖音',
                characteristics: [
                    '需要特定的User-Agent',
                    '从网页HTML的script标签中解析视频数据',
                    '数据可能在 __UNIVERSAL_DATA_FOR_REHYDRATION__ 或 SIGI_STATE 中',
                    '可能需要处理验证码挑战'
                ],
                apiEndpoint: 'https://www.douyin.com/aweme/v1/web/aweme/detail/',
                commonIssues: ['403错误', '空响应', '需要cookie验证']
            },
            tiktok: {
                name: 'TikTok',
                characteristics: [
                    '需要X-Bogus签名',
                    '需要msToken和ttwid',
                    '移动端API和Web端API不同'
                ],
                commonIssues: ['签名验证失败', 'IP被封禁']
            },
            youtube: {
                name: 'YouTube',
                characteristics: [
                    '推荐使用yt-dlp库',
                    '需要处理签名解密',
                    '有多种视频格式选择'
                ],
                commonIssues: ['速率限制', '需要登录']
            }
        };

        const info = platformInfo[platform] || { name: platform, characteristics: [], commonIssues: [] };

        return `为 ${info.name} 视频平台生成一个视频下载算法。

目标URL示例: ${url}

平台特征:
${info.characteristics.map((c, i) => `${i + 1}. ${c}`).join('\n')}

${info.apiEndpoint ? `已知API端点: ${info.apiEndpoint}` : ''}

常见问题:
${info.commonIssues.map((c, i) => `${i + 1}. ${c}`).join('\n')}

请生成一个完整的Python脚本，包含以下功能：
1. 提取视频ID
2. 获取视频信息（标题、作者、时长、点赞数等）
3. 获取无水印视频下载链接
4. 处理可能的错误和重试
5. 进度显示

以JSON格式返回，包含：
{
  "language": "python" | "nodejs",
  "code": "完整的可执行代码",
  "dependencies": ["依赖1", "依赖2"],
  "extractVideoId": "提取视频ID的函数说明",
  "extractInfo": "提取视频信息的方法",
  "extractVideoUrl": "提取视频URL的方法",
  "notes": "特殊说明",
  "estimatedSuccessRate": 0.85
}

确保代码可以直接运行，并处理所有边界情况。`;
    }

    /**
     * 解析AI返回的算法
     */
    parseAlgorithmResponse(response, platform) {
        try {
            const jsonMatch = response.match(/\{[\s\S]*\}/);
            if (!jsonMatch) {
                throw new Error('未找到JSON');
            }

            const algorithm = JSON.parse(jsonMatch[0]);

            return {
                platform,
                ...algorithm,
                timestamp: Date.now(),
                expiresAt: Date.now() + (3600000 * 24), // 24小时过期
                version: this.generateVersion()
            };
        } catch (error) {
            console.error('解析算法失败:', error.message);
            return this.getFallbackAlgorithm(platform);
        }
    }

    /**
     * 获取备用算法
     */
    getFallbackAlgorithm(platform) {
        const algorithms = {
            douyin: {
                language: 'python',
                code: fs.readFileSync(path.join(__dirname, 'douyin_web_api.py'), 'utf8'),
                dependencies: ['requests', 'urllib3'],
                extractVideoId: '正则匹配 /video/(\\d+)',
                extractInfo: '解析网页script标签中的JSON数据',
                extractVideoUrl: '从video.play_addr.url_list获取',
                notes: '使用facebookexternalhit UA',
                estimatedSuccessRate: 0.7
            },
            youtube: {
                language: 'python',
                code: 'import yt_dlp\n\ndef download_yt(url):\n    ydl_opts = {}\n    with yt_dlp.YoutubeDL(ydl_opts) as ydl:\n        info = ydl.extract_info(url, download=False)\n        return info',
                dependencies: ['yt-dlp'],
                extractVideoId: 'yt-dlp自动处理',
                extractInfo: 'yt-dlp自动处理',
                extractVideoUrl: 'yt-dlp自动处理',
                notes: '使用成熟的yt-dlp库',
                estimatedSuccessRate: 0.95
            }
        };

        return {
            platform,
            ...algorithms[platform],
            timestamp: Date.now(),
            expiresAt: Date.now() + (3600000 * 6),
            version: 'fallback-' + this.generateVersion()
        };
    }

    /**
     * 执行下载
     */
    async executeDownload(url, algorithm, outputDir) {
        if (algorithm.language === 'python') {
            return this.executePython(url, algorithm, outputDir);
        } else if (algorithm.language === 'nodejs') {
            return this.executeNode(url, algorithm, outputDir);
        } else {
            throw new Error(`不支持的语言: ${algorithm.language}`);
        }
    }

    /**
     * 执行Python脚本
     */
    executePython(url, algorithm, outputDir) {
        return new Promise((resolve, reject) => {
            const tempScript = path.join(__dirname, `temp_${algorithm.platform}_${Date.now()}.py`);

            try {
                // 写入临时脚本
                fs.writeFileSync(tempScript, algorithm.code);

                const args = [tempScript, url, 'download'];
                const python = this.getPythonCommand();

                const process = spawn(python, args);

                let stdout = '';
                let stderr = '';

                process.stdout.on('data', (data) => {
                    stdout += data.toString();
                });

                process.stderr.on('data', (data) => {
                    stderr += data.toString();
                });

                process.on('close', (code) => {
                    // 清理临时文件
                    try { fs.unlinkSync(tempScript); } catch {}

                    try {
                        const result = JSON.parse(stdout);
                        if (result.success) {
                            resolve(result);
                        } else {
                            reject(new Error(result.error || stderr));
                        }
                    } catch {
                        if (code === 0) {
                            resolve({ success: true, data: stdout });
                        } else {
                            reject(new Error(stderr || `进程退出码: ${code}`));
                        }
                    }
                });

                process.on('error', (err) => {
                    try { fs.unlinkSync(tempScript); } catch {}
                    reject(new Error(`Python执行错误: ${err.message}`));
                });
            } catch (error) {
                try { fs.unlinkSync(tempScript); } catch {}
                reject(error);
            }
        });
    }

    /**
     * 获取Python命令
     */
    getPythonCommand() {
        const possibilities = ['python', 'python3', 'python.exe'];
        return possibilities[0]; // 可以添加检测逻辑
    }

    /**
     * 检查算法是否过期
     */
    isAlgorithmExpired(algorithm) {
        if (!algorithm.expiresAt) return false;
        return Date.now() > algorithm.expiresAt;
    }

    /**
     * 生成版本号
     */
    generateVersion() {
        return Date.now().toString(36);
    }

    /**
     * 强制更新算法（手动触发AI重新生成）
     */
    async refreshAlgorithm(url) {
        const platform = this.detectPlatform(url);
        console.log(`强制刷新 ${platform} 的下载算法...`);

        const algorithm = await this.generateAlgorithm(url, platform);
        this.algorithms.set(platform, algorithm);

        return algorithm;
    }

    /**
     * 获取当前算法状态
     */
    getAlgorithmStatus(platform) {
        const algorithm = this.algorithms.get(platform);
        if (!algorithm) {
            return { status: 'not_loaded', platform };
        }

        return {
            status: 'loaded',
            platform,
            version: algorithm.version,
            age: Date.now() - algorithm.timestamp,
            expiresAt: algorithm.expiresAt,
            estimatedSuccessRate: algorithm.estimatedSuccessRate,
            isExpired: this.isAlgorithmExpired(algorithm)
        };
    }

    /**
     * 导出算法库
     */
    exportAlgorithms() {
        return {
            algorithms: Array.from(this.algorithms.entries()),
            lastUpdate: this.lastUpdate,
            exportTime: Date.now()
        };
    }

    /**
     * 导入算法库
     */
    importAlgorithms(data) {
        if (data.algorithms) {
            this.algorithms = new Map(data.algorithms);
        }
        if (data.lastUpdate) {
            this.lastUpdate = data.lastUpdate;
        }
    }

    /**
     * 智能重试：失败后自动请求AI更新策略
     */
    async downloadWithRetry(url, maxRetries = 3) {
        let lastError;

        for (let attempt = 1; attempt <= maxRetries; attempt++) {
            try {
                // 第一次使用缓存的算法，后续尝试强制AI重新生成
                const options = {
                    forceAIAnalysis: attempt > 1
                };

                const result = await this.download(url, options);

                // 记录成功
                const platform = this.detectPlatform(url);
                this.antiScraper.recordResult(platform, true, { attempt });

                return result;
            } catch (error) {
                lastError = error;
                console.log(`尝试 ${attempt}/${maxRetries} 失败: ${error.message}`);

                const platform = this.detectPlatform(url);
                this.antiScraper.recordResult(platform, false, {
                    attempt,
                    error: error.message
                });

                // 如果不是最后一次尝试，请求AI生成新策略
                if (attempt < maxRetries) {
                    console.log('请求AI分析失败原因并更新策略...');
                    await this.antiScraper.adaptStrategy(new URL(url).hostname, {
                        message: error.message,
                        forceAnalysis: true
                    });

                    // 刷新算法
                    await this.refreshAlgorithm(url);
                }
            }
        }

        throw lastError;
    }
}

module.exports = DynamicDownloader;

