const { ipcMain } = require('electron');
const path = require('path');
const { spawn } = require('child_process');
const os = require('os');

// 在线解析 API 配置
const PARSE_APIs = {
    douyin: 'https://douyin.wtf/api', // 备用 API
    tiktok: 'https://douyin.wtf/api',
    // 可以添加更多备用 API
};

async function fetchVideoInfo(url) {
    // 判断平台
    const platform = detectPlatform(url);

    if (platform === 'youtube') {
        return await fetchYouTubeInfo(url);
    } else if (platform === 'douyin' || platform === 'tiktok') {
        return await fetchDouyinInfo(url);
    }

    return { success: false, error: '不支持的平台' };
}

function detectPlatform(url) {
    url = url.toLowerCase();
    if (url.includes('youtube.com') || url.includes('youtu.be')) return 'youtube';
    if (url.includes('douyin.com') || url.includes('iesdouyin.com')) return 'douyin';
    if (url.includes('tiktok.com')) return 'tiktok';
    return 'unknown';
}

// YouTube 使用 yt-dlp
async function fetchYouTubeInfo(url) {
    return new Promise((resolve) => {
        const cmd = 'yt-dlp';
        const args = ['--dump-json', '--no-playlist', url];
        const process = spawn(cmd, args);

        let stdout = '';
        let stderr = '';

        process.stdout.on('data', (data) => { stdout += data.toString(); });
        process.stderr.on('data', (data) => { stderr += data.toString(); });

        process.on('close', (code) => {
            if (code === 0) {
                try {
                    const info = JSON.parse(stdout);
                    resolve({ success: true, info: formatYouTubeInfo(info) });
                } catch (e) {
                    resolve({ success: false, error: '解析失败' });
                }
            } else {
                resolve({ success: false, error: stderr || '获取失败' });
            }
        });

        process.on('error', () => {
            resolve({ success: false, error: 'yt-dlp 未安装' });
        });
    });
}

// 抖音使用在线 API
async function fetchDouyinInfo(url) {
    try {
        // 方法1: 使用第三方解析 API
        const apiUrl = `https://api.pearktrue.com/api/v1/parse/douyin?url=${encodeURIComponent(url)}`;

        const response = await fetch(apiUrl);
        const data = await response.json();

        if (data.code === 200 && data.data) {
            return {
                success: true,
                info: formatDouyinInfo(data.data)
            };
        }

        // 方法2: 尝试另一个 API
        const api2Url = `https://www.hyperikun.com/api/douyin?url=${encodeURIComponent(url)}`;
        const response2 = await fetch(api2Url);
        const data2 = await response2.json();

        if (data2.code === 200 && data2.data) {
            return {
                success: true,
                info: formatDouyinInfo(data2.data)
            };
        }

        return { success: false, error: '解析失败，请稍后重试' };
    } catch (error) {
        return { success: false, error: '网络错误: ' + error.message };
    }
}

function formatYouTubeInfo(info) {
    const platformName = 'YouTube';
    return `📹 标题：${info.title || 'N/A'}

👤 ${platformName}号：${info.channel || info.uploader || 'N/A'}
⏱️ 时长：${formatDuration(info.duration)}
👁️ 观看：${formatViews(info.view_count)}

📅 上传：${info.upload_date ? info.upload_date.substring(0, 10) : 'N/A'}
🔗 链接：${info.webpage_url || url}

📝 描述：
${info.description ? info.description.substring(0, 200) + (info.description.length > 200 ? '...' : '') : '无描述'}`;
}

function formatDouyinInfo(data) {
    const platformName = '抖音';
    return `📹 标题：${data.desc || data.title || 'N/A'}

👤 ${platformName}号：${data.author?.nickname || data.uploader || 'N/A'}
⏱️ 时长：${data.duration ? formatDuration(data.duration / 1000) : 'N/A'}

📅 发布：${data.create_time ? new Date(data.create_time * 1000).toLocaleDateString() : 'N/A'}
🔗 链接：${data.share_url || data.url || url}

📝 描述：
${(data.desc || '无描述').substring(0, 200)}

👍 点赞：${data.statistics?.digg_count || 'N/A'}
💬 评论：${data.statistics?.comment_count || 'N/A'}`;
}

function formatDuration(seconds) {
    if (!seconds) return 'N/A';
    const hours = Math.floor(seconds / 3600);
    const minutes = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);

    if (hours > 0) {
        return `${hours}:${minutes.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
    return `${minutes}:${secs.toString().padStart(2, '0')}`;
}

function formatViews(count) {
    if (!count) return 'N/A';
    if (count >= 1000000) return `${(count / 1000000).toFixed(1)}M`;
    if (count >= 1000) return `${(count / 1000).toFixed(1)}K`;
    return String(count);
}

// 导出函数
module.exports = { fetchVideoInfo, detectPlatform };

