package com.multilanglearner.data.network

import okhttp3.OkHttpClient
import okhttp3.Request
import org.json.JSONArray
import org.json.JSONObject
import java.io.IOException
import java.util.concurrent.TimeUnit

/**
 * 视频下载服务 - 使用公共 API 获取视频信息
 * 支持 YouTube, B站, 抖音等平台
 */
class VideoDownloadService {

    private val client = OkHttpClient.Builder()
        .connectTimeout(30, TimeUnit.SECONDS)
        .readTimeout(30, TimeUnit.SECONDS)
        .build()

    /**
     * 获取视频信息
     * 使用 tube.knck.ai 这个免费的 yt-dlp API
     */
    suspend fun getVideoInfo(url: String): VideoInfo? {
        // 使用 tube.knck.ai 公共 API
        val apiUrl = "https://tube.knck.ai/api/json"

        val body = JSONObject().apply {
            put("url", url)
        }.toString()

        val request = Request.Builder()
            .url(apiUrl)
            .addHeader("Content-Type", "application/json")
            .post(okhttp3.RequestBody.create(body.toRequestBody(), okhttp3.MediaType.parse("application/json")!!))
            .build()

        return try {
            val response = client.newCall(request).execute()
            if (!response.isSuccessful) {
                return null
            }

            val responseBody = response.body?.string() ?: return null
            parseVideoInfo(responseBody)
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    private fun parseVideoInfo(json: String): VideoInfo? {
        return try {
            val obj = JSONObject(json)

            // 尝试多种可能的响应格式
            val title = when {
                obj.has("title") -> obj.getString("title")
                obj.has("fulltitle") -> obj.getString("fulltitle")
                else -> "Video"
            }

            val thumbnail = when {
                obj.has("thumbnail") -> obj.getString("thumbnail")
                obj.has("cover") -> obj.getString("cover")
                else -> null
            }

            // 获取视频 URL
            val videoUrl = extractVideoUrl(obj)

            VideoInfo(
                title = title,
                thumbnail = thumbnail,
                videoUrl = videoUrl,
                duration = obj.optLong("duration", 0),
                author = obj.optString("uploader", obj.optString("channel", ""))
            )
        } catch (e: Exception) {
            e.printStackTrace()
            null
        }
    }

    private fun extractVideoUrl(obj: JSONObject): String? {
        // 尝试从不同字段获取视频 URL
        if (obj.has("url")) return obj.getString("url")

        // 从 formats 数组中获取最佳质量
        if (obj.has("formats")) {
            val formats = obj.getJSONArray("formats")
            for (i in 0 until formats.length()) {
                val format = formats.getJSONObject(i)
                if (format.optString("ext") == "mp4") {
                    val formatId = format.optString("format_id", "")
                    // 优先选择视频+音频合并的格式
                    if (formatId.contains("+") || format.optString("vcodec", "none") != "none") {
                        return format.getString("url")
                    }
                }
            }
            // 如果没有找到理想的，返回第一个 mp4
            for (i in 0 until formats.length()) {
                val format = formats.getJSONObject(i)
                if (format.optString("ext") == "mp4") {
                    return format.getString("url")
                }
            }
        }

        // 从 url 字段获取
        if (obj.has("webpage_url")) {
            return obj.getString("webpage_url")
        }

        return null
    }

    /**
     * 视频信息数据类
     */
    data class VideoInfo(
        val title: String,
        val thumbnail: String?,
        val videoUrl: String?,
        val duration: Long,
        val author: String
    )

    private fun String.toRequestBody(): okhttp3.RequestBody {
        return okhttp3.RequestBody.create(
            okhttp3.MediaType.parse("application/json")!!,
            this
        )
    }
}

