package com.multilanglearner.ui.home

import android.app.Application
import android.content.Context
import android.net.Uri
import androidx.lifecycle.AndroidViewModel
import androidx.lifecycle.viewModelScope
import com.multilanglearner.data.db.entity.VideoEntity
import com.multilanglearner.data.repository.VideoRepository
import com.multilanglearner.data.store.ThemeStore
import dagger.hilt.android.lifecycle.HiltViewModel
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.flow.*
import kotlinx.coroutines.launch
import kotlinx.coroutines.withContext
import okhttp3.OkHttpClient
import java.io.File
import java.io.FileOutputStream
import javax.inject.Inject

data class HomeUiState(
    val url: String = "",
    val selectedLang: String = "en",
    val isDownloading: Boolean = false,
    val downloadProgress: Float = 0f,
    val statusText: String = "",
    val videos: List<VideoEntity> = emptyList()
)

@HiltViewModel
class HomeViewModel @Inject constructor(
    application: Application,
    private val videoRepository: VideoRepository,
    private val themeStore: ThemeStore
) : AndroidViewModel(application) {
    private val _uiState = MutableStateFlow(HomeUiState())
    val uiState: StateFlow<HomeUiState> = _uiState.asStateFlow()

    private val downloadsDir: File = File(application.filesDir, "downloads").also { it.mkdirs() }

    init {
        viewModelScope.launch {
            videoRepository.getAll().collect { videos ->
                _uiState.update { it.copy(videos = videos) }
            }
        }
    }

    fun setUrl(url: String) { _uiState.update { it.copy(url = url) } }
    fun setLang(lang: String) { _uiState.update { it.copy(selectedLang = lang) } }

    fun setTheme(theme: String) { viewModelScope.launch { themeStore.setTheme(theme) } }
    fun setFontSize(size: String) { viewModelScope.launch { themeStore.setFontSize(size) } }

    /**
     * 下载视频 - 简化版本
     * 由于 Android 环境限制，当前版本仅支持：
     * 1. 直接视频 URL (mp4, webm 等直链)
     * 2. B站等平台需要使用导入功能（先用电脑下载）
     *
     * 建议：使用导入功能选择已下载的视频文件
     */
    fun downloadVideo(onComplete: (String, String?) -> Unit) {
        val url = _uiState.value.url.trim()
        android.util.Log.d("MultiLangLearner", "Download clicked, url: $url, isBlank: ${url.isBlank()}")

        if (url.isBlank()) {
            _uiState.update { it.copy(statusText = "请输入视频链接") }
            return
        }

        // 检查是否是直链视频
        val isDirect = isDirectVideoUrl(url)
        android.util.Log.d("MultiLangLearner", "isDirectVideoUrl: $isDirect")

        if (!isDirect) {
            _uiState.update { it.copy(statusText = "当前仅支持直链视频(.mp4等)\n请使用\"导入\"功能选择本地视频") }
            android.util.Log.d("MultiLangLearner", "Not a direct video URL, showing hint")
            return
        }

        _uiState.update { it.copy(isDownloading = true, downloadProgress = 0f, statusText = "正在下载...") }
        android.util.Log.d("MultiLangLearner", "Starting download for: $url")

        viewModelScope.launch(Dispatchers.IO) {
            try {
                downloadDirectVideo(url, onComplete)
            } catch (e: Exception) {
                android.util.Log.e("MultiLangLearner", "Download failed", e)
                _uiState.update { it.copy(isDownloading = false, statusText = "下载失败: ${e.message}") }
            }
        }
    }

    private fun isDirectVideoUrl(url: String): Boolean {
        val lowerUrl = url.lowercase()

        // 排除需要特殊处理的平台
        val excludedPlatforms = listOf(
            "bilibili.com", "douyin.com", "tiktok.com", "youtube.com",
            "youtu.be", "weibo.com", "xiaohongshu.com", "xhslink.com",
            "kuaishou.com", "ixigua.com"
        )

        for (platform in excludedPlatforms) {
            if (lowerUrl.contains(platform)) {
                return false
            }
        }

        // 检查是否是直链视频
        return lowerUrl.contains(".mp4") ||
               lowerUrl.contains(".webm") ||
               lowerUrl.contains(".m3u8") ||
               // 检查常见的直链CDN域名
               (lowerUrl.contains("cdn") && (lowerUrl.contains("video") || lowerUrl.contains("media")))
    }

    private suspend fun downloadDirectVideo(url: String, onComplete: (String, String?) -> Unit) {
        val request = okhttp3.Request.Builder()
            .url(url)
            .build()

        val client = OkHttpClient.Builder()
            .connectTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
            .readTimeout(30, java.util.concurrent.TimeUnit.SECONDS)
            .build()

        val response = client.newCall(request).execute()

        if (!response.isSuccessful) {
            throw Exception("HTTP ${response.code}")
        }

        val body = response.body ?: throw Exception("No response body")
        val contentLength = body.contentLength()
        val inputStream = body.byteStream()

        // 生成文件名
        val fileName = "video_${System.currentTimeMillis()}.mp4"
        val outputFile = File(downloadsDir, fileName)

        var bytesCopied = 0L
        val buffer = ByteArray(8 * 1024)
        var bytes: Int

        inputStream.use { input ->
            FileOutputStream(outputFile).use { output ->
                while (input.read(buffer).also { bytes = it } > 0) {
                    output.write(buffer, 0, bytes)
                    bytesCopied += bytes

                    if (contentLength > 0) {
                        val progress = (bytesCopied * 100 / contentLength).toInt()
                        _uiState.update { it.copy(downloadProgress = progress / 100f, statusText = "下载中 ${progress}%") }
                    }
                }
            }
        }

        // 保存到数据库
        val entity = VideoEntity(
            title = fileName.substringBeforeLast("."),
            filePath = outputFile.absolutePath,
            vttPath = null,
            language = _uiState.value.selectedLang,
            sourceUrl = url
        )
        videoRepository.insert(entity)

        _uiState.update { it.copy(isDownloading = false, statusText = "下载完成!", url = "") }

        withContext(Dispatchers.Main) {
            onComplete(outputFile.absolutePath, null)
        }
    }

    fun importVideo(context: Context, uri: Uri, onComplete: (String, String?) -> Unit) {
        viewModelScope.launch(Dispatchers.IO) {
            try {
                _uiState.update { it.copy(statusText = "正在导入..." ) }

                // 获取文件名
                val fileName = getFileName(context, uri) ?: "import_${System.currentTimeMillis()}.mp4"
                val tempFile = File(downloadsDir, fileName)

                // 复制文件
                val inputStream = context.contentResolver.openInputStream(uri)
                val outputStream = FileOutputStream(tempFile)

                inputStream?.use { input ->
                    outputStream.use { output ->
                        input.copyTo(output)
                    }
                }

                val entity = VideoEntity(
                    title = tempFile.nameWithoutExtension,
                    filePath = tempFile.absolutePath,
                    vttPath = null,
                    language = _uiState.value.selectedLang,
                    sourceUrl = null
                )
                videoRepository.insert(entity)

                _uiState.update { it.copy(statusText = "导入完成!", url = "") }
                launch(Dispatchers.Main) { onComplete(tempFile.absolutePath, null) }
            } catch (e: Exception) {
                android.util.Log.e("MultiLangLearner", "Import failed", e)
                _uiState.update { it.copy(statusText = "导入失败: ${e.message}") }
            }
        }
    }

    private fun getFileName(context: Context, uri: Uri): String? {
        var result: String? = null
        if (uri.scheme == "content") {
            val cursor = context.contentResolver.query(uri, null, null, null, null)
            cursor?.use {
                if (it.moveToFirst()) {
                    val index = it.getColumnIndex(android.provider.OpenableColumns.DISPLAY_NAME)
                    if (index >= 0) result = it.getString(index)
                }
            }
        }
        if (result == null) {
            result = uri.path
            val cut = result?.lastIndexOf('/')
            if (cut != -1) {
                result = result?.substring(cut!! + 1)
            }
        }
        return result
    }
}

