                            ExposedDropdownMenu(expanded = langExpanded, onDismissRequest = { langExpanded = false }) {
                                LANGUAGES.forEach { lang ->
                                    DropdownMenuItem(
                                        text = { Text(lang.name) },
                                        onClick = { viewModel.setLang(lang.code); langExpanded = false }
                                    )
                                }
                            }
                        }

                        Spacer(Modifier.width(8.dp))
                        Button(
                            onClick = { viewModel.downloadVideo { path, sub -> onNavigateToPlayer(path, sub) } },
                            enabled = uiState.url.isNotBlank() && !uiState.isDownloading
                        ) { Text("下载") }

                        Spacer(Modifier.width(4.dp))
                        OutlinedButton(onClick = { videoPickerLauncher.launch("video/*") }) {
                            Icon(Icons.Default.FolderOpen, null, Modifier.size(16.dp))
                            Spacer(Modifier.width(4.dp))
                            Text("导入")
                        }
                    }

                    // Progress bar
                    if (uiState.isFetchingInfo || uiState.isDownloading) {
                        Spacer(Modifier.height(8.dp))
                        LinearProgressIndicator(
                            modifier = Modifier.fillMaxWidth(),
                            color = MaterialTheme.colorScheme.primary
                        )
                        Text(
                            uiState.statusText,
                            style = MaterialTheme.typography.bodySmall,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    } else if (uiState.statusText.isNotEmpty()) {
                        Spacer(Modifier.height(4.dp))
                        Text(
                            uiState.statusText,
                            style = MaterialTheme.typography.bodySmall,
                            color = if (uiState.statusText.contains("失败") || uiState.statusText.contains("错误"))
                                MaterialTheme.colorScheme.error else MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }

            Spacer(Modifier.height(8.dp))

            // Function buttons row
            Row(
                modifier = Modifier.fillMaxWidth(),
                horizontalArrangement = Arrangement.spacedBy(8.dp)
            ) {
                AssistChip(onClick = { showAISettings = true }, label = { Text("AI") },
                    leadingIcon = { Icon(Icons.Default.Settings, null, Modifier.size(16.dp)) })
                AssistChip(onClick = onNavigateToVocabulary, label = { Text("词书") },
                    leadingIcon = { Icon(Icons.Default.Book, null, Modifier.size(16.dp)) })
                AssistChip(onClick = { showAssistant = true }, label = { Text("助手") },
                    leadingIcon = { Icon(Icons.Default.Mic, null, Modifier.size(16.dp)) })
                AssistChip(onClick = onNavigateToRegulation, label = { Text("法规") },
                    leadingIcon = { Icon(Icons.Default.Gavel, null, Modifier.size(16.dp)) })
            }

            Spacer(Modifier.height(12.dp))

            // Video list
            Text("已下载视频", style = MaterialTheme.typography.titleMedium)
            Spacer(Modifier.height(8.dp))

            if (uiState.videos.isEmpty()) {
                Box(Modifier.fillMaxWidth().padding(32.dp), contentAlignment = Alignment.Center) {
                    Text("暂无视频，请下载或导入", color = MaterialTheme.colorScheme.onSurfaceVariant)
                }
            } else {
                LazyColumn(verticalArrangement = Arrangement.spacedBy(8.dp)) {
                    items(uiState.videos) { video ->
                        Card(
                            onClick = { onNavigateToPlayer(video.filePath, video.vttPath) },
                            modifier = Modifier.fillMaxWidth()
                        ) {
                            Row(
                                modifier = Modifier.padding(16.dp),
                                verticalAlignment = Alignment.CenterVertically
                            ) {
                                Icon(Icons.Default.VideoLibrary, null,
                                    tint = MaterialTheme.colorScheme.primary)
                                Spacer(Modifier.width(12.dp))
                                Column(Modifier.weight(1f)) {
                                    Text(video.title, style = MaterialTheme.typography.bodyLarge)
                                    Text(
                                        if (video.vttPath != null) "有字幕" else "无字幕",
                                        style = MaterialTheme.typography.bodySmall,
                                        color = MaterialTheme.colorScheme.onSurfaceVariant
                                    )
                                }
                            }
                        }
                    }
                }
            }
        }
