                .header("User-Agent", "Mozilla/5.0")
                .build()

            val response = client.newCall(request).execute()
            val responseBody = response.body?.string() ?: return Result.failure(IOException("空响应"))

            val json = JSONObject(responseBody)
            if (json.optInt("code") == 200 && json.has("data")) {
                val data = json.getJSONObject("data")
                Result.success(VideoDownloadInfo(
                    title = data.optString("desc", "抖音视频"),
                    downloadUrl = data.optString("play_addr"),
                    cover = data.optString("cover")
                ))
            } else {
                Result.failure(Exception("解析失败"))
            }
        } catch (e: Exception) {
            Result.failure(e)
        }
    }

    /**
     * 获取 TikTok 视频信息
     */
    private suspend fun fetchTiktokInfo(url: String): Result<VideoDownloadInfo> {
        return try {
            // 使用抖音相同的 API，TikTok 和抖音结构类似
            fetchDouyinInfo(url)
        } catch (e: Exception) {
            Result.failure(Exception("TikTok 解析失败: ${e.message}"))
        }
    }

