            val json = JSONObject(responseBody)
            if (json.has("code") && json.getInt("code") == 0 && json.has("data")) {
                val data = json.getJSONObject("data")
                val title = data.optString("title", "B站视频")

                // 获取视频流
                val pages = data.optJSONArray("pages") ?: return Result.success(VideoDownloadInfo(title, url, null, 0L, null))

                // 使用cid获取视频流
                val cid = data.optJSONObject("stat")?.optString("aid")
                    ?: data.optJSONObject("owner")?.optString("mid")
                    ?: "0"

